SELECT COALESCE(SUM(quantity), 0)
FROM material_inventory
WHERE material_id = #{materialId}

SELECT COALESCE(SUM(reserved_qty), 0)
FROM material_reservation
WHERE material_id = #{materialId}

SELECT COALESCE(SUM(reserved_qty), 0)
FROM material_reservation
WHERE work_order_id = #{workOrderId}
  AND material_id   = #{materialId}

SELECT COALESCE(SUM(reserved_qty),0)
FROM material_reservation
WHERE material_id = #{materialId}

SELECT COALESCE(reserved_qty,0)
FROM material_reservation
WHERE work_order_id = #{workOrderId}
  AND material_id   = #{materialId}

mapper.update:
UPDATE material_reservation
SET reserved_qty = GREATEST(reserved_qty - #{qty}, 0),
    updated_at   = CURRENT_TIMESTAMP
WHERE work_order_id = #{workOrderId}
  AND material_id   = #{materialId}

UPDATE work_order
   SET shortage_status     = #{status},
       shortage_checked_at = NOW(),
       shortage_checked_by = #{userId}
 WHERE order_id = #{workOrderId}

UPDATE work_order
   SET shortage_status     = #{to},
       shortage_checked_at = NOW()
 WHERE order_id = #{workOrderId}
   AND shortage_status = #{from}
